import { defineComponentStyle } from "@yamada-ui/react"

export const scrollAreaStyle = defineComponentStyle({
  base: {
    "@-moz-document url-prefix()": {
      scrollbarColor: "{colors.bg.emphasized} transparent",
      _dark: {
        scrollbarColor: "{colors.bg.emphasized} transparent",
      },
      _light: {
        scrollbarColor: "{colors.bg.emphasized} transparent",
      },
    },
    overflow: "auto",
    _scrollbar: {
      boxSize: "3",
    },
    _scrollbarCorner: {
      bg: "transparent",
    },
    _scrollbarThumb: {
      bg: "bg.emphasized",
      bgClip: "padding-box",
      border: "3px solid transparent",
      rounded: "full",
      _nativeHover: {
        bg: "bg.contrast",
        bgClip: "padding-box",
      },
    },
    _scrollbarTrack: {
      bg: "transparent",
    },
    _hidden: {
      "&::-webkit-scrollbar-thumb": { bg: "transparent" },
      "&::-webkit-scrollbar-track": { bg: "transparent" },
      "@-moz-document url-prefix()": {
        scrollbarColor: "transparent transparent",
        _dark: {
          scrollbarColor: "transparent transparent",
        },
        _light: {
          scrollbarColor: "transparent transparent",
        },
      },
      _dark: {
        "&::-webkit-scrollbar-thumb": { bg: "transparent" },
        "&::-webkit-scrollbar-track": { bg: "transparent" },
        _scrollbarThumb: { bg: "transparent" },
        _scrollbarTrack: { bg: "transparent" },
      },
      _light: {
        "&::-webkit-scrollbar-thumb": { bg: "transparent" },
        "&::-webkit-scrollbar-track": { bg: "transparent" },
        _scrollbarThumb: { bg: "transparent" },
        _scrollbarTrack: { bg: "transparent" },
      },
      _scrollbarThumb: { bg: "transparent" },
      _scrollbarTrack: { bg: "transparent" },
    },
    _never: {
      "&::-webkit-scrollbar": { display: "none" },
      scrollbarWidth: "none",
      _scrollbar: { display: "none" },
    },
  },
})

export type ScrollAreaStyle = typeof scrollAreaStyle

import { page, render } from "#test/browser"
import { ScrollArea } from "."
import { useScrollArea } from "./use-scroll-area"

const stubNavigator = (overrides: {
  platform?: string
  userAgentData?: { platform: string }
  vendor?: string
}) => {
  const descriptors: { [key: string]: PropertyDescriptor | undefined } = {
    platform: Object.getOwnPropertyDescriptor(window.navigator, "platform"),
    userAgentData: Object.getOwnPropertyDescriptor(
      window.navigator,
      "userAgentData",
    ),
    vendor: Object.getOwnPropertyDescriptor(window.navigator, "vendor"),
  }

  for (const [key, value] of Object.entries(overrides)) {
    Object.defineProperty(window.navigator, key, {
      configurable: true,
      value,
    })
  }

  return () => {
    for (const [key, descriptor] of Object.entries(descriptors)) {
      if (descriptor) {
        Object.defineProperty(window.navigator, key, descriptor)
      } else {
        Reflect.deleteProperty(window.navigator, key)
      }
    }
  }
}

describe("<ScrollArea />", () => {
  test("applies safari specific key format", async () => {
    const restore = stubNavigator({
      platform: "MacIntel",
      userAgentData: { platform: "macOS" },
      vendor: "Apple Computer, Inc.",
    })

    try {
      await render(
        <ScrollArea type="never" data-testid="scroll-area">
          <p>Content</p>
        </ScrollArea>,
      )

      const scrollArea = page.getByTestId("scroll-area")
      const key = scrollArea.element().getAttribute("data-key")

      await expect.element(scrollArea).toHaveAttribute("data-key")
      expect(key).toMatch(/-false-false$/)
    } finally {
      restore()
    }
  })

  test("composes refs once in safari root props", async () => {
    const restore = stubNavigator({
      platform: "MacIntel",
      userAgentData: { platform: "macOS" },
      vendor: "Apple Computer, Inc.",
    })

    try {
      const externalRef = vi.fn()
      const consumerRef = vi.fn()

      const Component = () => {
        const { getRootProps } = useScrollArea({
          ref: externalRef,
        })

        return (
          <div
            data-testid="scroll-area-ref"
            {...getRootProps({ ref: consumerRef })}
          />
        )
      }

      await render(<Component />)

      const scrollArea = page.getByTestId("scroll-area-ref")
      const node = scrollArea.element()

      await expect.element(scrollArea).toHaveAttribute("data-key")
      expect(externalRef).toHaveBeenCalledWith(node)
      expect(consumerRef).toHaveBeenCalledWith(node)
      expect(
        externalRef.mock.calls.filter(([value]) => value === node),
      ).toHaveLength(1)
      expect(
        consumerRef.mock.calls.filter(([value]) => value === node),
      ).toHaveLength(1)
    } finally {
      restore()
    }
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { ScrollAreaStyle } from "./scroll-area.style"
import type { UseScrollAreaProps } from "./use-scroll-area"
import { createComponent, styled } from "@yamada-ui/react"
import { scrollAreaStyle } from "./scroll-area.style"
import { useScrollArea } from "./use-scroll-area"

export interface ScrollAreaProps
  extends HTMLStyledProps, ThemeProps<ScrollAreaStyle>, UseScrollAreaProps {}

const {
  PropsContext: ScrollAreaPropsContext,
  usePropsContext: useScrollAreaPropsContext,
  withContext,
} = createComponent<ScrollAreaProps, ScrollAreaStyle>(
  "scroll-area",
  scrollAreaStyle,
)

export { ScrollAreaPropsContext, useScrollAreaPropsContext }

/**
 * `ScrollArea` is a component that displays a customized scrollbar.
 *
 * @see https://yamada-ui.com/docs/components/scroll-area
 */
export const ScrollArea = withContext<"div", ScrollAreaProps>(
  ({ children, ...rest }) => {
    const { getRootProps } = useScrollArea(rest)

    return <styled.div {...getRootProps()}>{children}</styled.div>
  },
)()

"use client"

import type { UIEvent } from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import { useCallback, useEffect, useId, useRef, useState } from "react"
import {
  mergeProps,
  dataAttr,
  isMac,
  useSafeLayoutEffect,
  vendor,
} from "@yamada-ui/react"

export interface UseScrollAreaProps extends HTMLProps {
  /**
   * Delay in milliseconds before scrollbars are hidden.
   *
   * @default 1000
   */
  scrollHideDelay?: number
  /**
   * Scrollbar visibility type.
   *
   * @default 'hover'
   */
  type?: "always" | "hover" | "never" | "scroll"
  /**
   * Callback function for when the scroll position changes.
   */
  onScrollPositionChange?: ({ x, y }: { x: number; y: number }) => void
}

export const useScrollArea = ({
  id,
  type = "hover",
  scrollHideDelay = 1000,
  onScrollPositionChange,
  ...rest
}: UseScrollAreaProps = {}) => {
  const [isHovered, setIsHovered] = useState<boolean>(false)
  const [isScrolling, setIsScrolling] = useState<boolean>(false)
  const isAlways = type === "always"
  const isNever = type === "never"
  const isHidden = !isAlways && !isHovered && !isScrolling
  const isSafari = isMac() && vendor(/apple/i)
  const uuid = useId()
  const key = `${id ?? uuid}-${isHovered}-${isScrolling}`

  const hoverTimeout = useRef<any>(undefined)
  const scrollTimeout = useRef<any>(undefined)
  const scrollAreaRef = useRef<HTMLDivElement>(null)
  const scrollPosition = useRef({ x: 0, y: 0 })

  useSafeLayoutEffect(() => {
    if (!scrollAreaRef.current || !isSafari) return

    scrollAreaRef.current.scrollLeft = scrollPosition.current.x
    scrollAreaRef.current.scrollTop = scrollPosition.current.y
  })

  const onMouseEnter = useCallback(() => {
    if (type !== "hover") return

    clearTimeout(hoverTimeout.current)

    setIsHovered(true)
  }, [type])

  const onMouseLeave = useCallback(() => {
    if (type !== "hover") return

    hoverTimeout.current = setTimeout(
      () => setIsHovered(false),
      scrollHideDelay,
    )
  }, [scrollHideDelay, type])

  const onScroll = useCallback(
    (ev: UIEvent<HTMLDivElement>) => {
      const el = ev.target as HTMLDivElement

      const { scrollLeft: x, scrollTop: y } = el
      const { x: prevX, y: prevY } = scrollPosition.current
      const isEqual = Math.abs(x - prevX) <= 5 && Math.abs(y - prevY) <= 5

      onScrollPositionChange?.({ x, y })
      scrollPosition.current = { x, y }

      if (type !== "scroll" || isEqual) return

      if (!isScrolling) setIsScrolling(true)

      clearTimeout(scrollTimeout.current)

      scrollTimeout.current = setTimeout(
        () => setIsScrolling(false),
        scrollHideDelay,
      )
    },
    [isScrolling, onScrollPositionChange, scrollHideDelay, type],
  )

  useEffect(() => {
    return () => {
      if (hoverTimeout.current) clearTimeout(hoverTimeout.current)
      if (scrollTimeout.current) clearTimeout(scrollTimeout.current)
    }
  }, [])

  const getRootProps: PropGetter = useCallback(
    (props = {}) =>
      mergeProps(
        {
          style: { overflow: "auto" },
          "data-hidden": dataAttr(isHidden),
          "data-hover": dataAttr(isHovered),
          "data-never": dataAttr(isNever),
          "data-scroll": dataAttr(isScrolling),
          tabIndex: 0,
        },
        isSafari ? { key, ref: scrollAreaRef, "data-key": key } : {},
        rest,
        props,
        {
          onMouseEnter,
          onMouseLeave,
          onPointerEnter: onMouseEnter,
          onPointerLeave: onMouseLeave,
          onScroll,
        },
      )(),
    [
      isNever,
      isHidden,
      isHovered,
      isScrolling,
      isSafari,
      key,
      rest,
      onMouseEnter,
      onMouseLeave,
      onScroll,
    ],
  )

  return {
    isAlways,
    isHidden,
    isHovered,
    isNever,
    isScrolling,
    getRootProps,
  }
}

export type UseScrollAreaReturn = ReturnType<typeof useScrollArea>
